function afficherMessage(nom, score) {
  let msg = `Félicitations ${nom} ! Ton score est de ${score} points.`;
  if (score >= 10) msg += " Excellent niveau !";
  return msg;
}

function validerInscription(pseudo, email, codePostal) {
  const pseudoValide = pseudo.length >= 3 && /^[A-Za-z]/.test(pseudo);
  const emailValide = email.includes('@') && email.endsWith('.cm');
  const codeValide = codePostal.length === 5 && !isNaN(parseInt(codePostal)) && /^\d{5}$/.test(codePostal);
  return pseudoValide && emailValide && codeValide;
}
